class Solution {
public:
    vector<long long> unmarkedSumArray(vector<int>& nums, vector<vector<int>>& queries) {
        vector<long long> res;
        vector<int> marked(nums.size(), 0);
        for (auto& query : queries) {
            int idx = query[0];
            int k = query[1];
            if (!marked[idx]) {
                marked[idx] = 1;
            }
            vector<int> unmarked;
            for (int i = 0; i < nums.size(); i++) {
                if (!marked[i]) {
                    unmarked.push_back(nums[i]);
                }
            }
            sort(unmarked.begin(), unmarked.end());
            for (int i = 0; i < k && i < unmarked.size(); i++) {
                marked[lower_bound(unmarked.begin(), unmarked.end(), unmarked[i]) - unmarked.begin()] = 1;
            }
            long long sum = 0;
            for (int i = 0; i < nums.size(); i++) {
                if (!marked[i]) {
                    sum += nums[i];
                }
            }
            res.push_back(sum);
        }
        return res;
    }
};
